Bash(PGPASSWORD=admin psql -h localhost -p 54320 -U admin -d tradingdb -c "
SELECT schemaname, tablename FROM pg_tables WHERE schemaname = 'stock_ai';
SELECT symbol, COUNT\(*\) AS rows, MIN\(date\) AS from_date, MAX\(date\) AS to_date
  FROM stock_ai.ohlcv_factors GROUP BY symbol ORDER BY symbol;
SELECT symbol, COUNT\(*\) AS signal_rows, SUM\(CASE WHEN signal=1 THEN 1 ELSE 0 END\) AS buy, SUM\(CASE WHEN signal=-1 THEN 1 ELSE 0 END\) AS sell
  FROM stock_ai.signals GROUP BY symbol ORDER BY symbol;
" 2>&1)
